-/// Connection-scoped environment for selecting the runtime context.
+/// Connection-scoped environment for selecting the runtime context and
+/// tuning resource limits.
+///
+/// # Page buffer pool sizing
+///
+/// By default the page-buffer pool is sized via the `FSQLITE_PAGE_BUFFER_MAX`
+/// environment variable (if set), otherwise
+/// [`DEFAULT_PAGE_BUFFER_MAX`](fsqlite_pager::DEFAULT_PAGE_BUFFER_MAX)
+/// (262 144 buffers ≈ 1 GiB at 4 KiB pages).
+///
+/// To override programmatically, call
+/// [`set_page_buffer_max`](Self::set_page_buffer_max) before opening a
+/// connection:
+///
+/// ```ignore
+/// let mut env = ConnectionEnv::default();
+/// env.set_page_buffer_max(524_288); // 2 GiB at 4 KiB pages
+/// let conn = Connection::open_with_env("big.db", env)?;
+/// ```
 #[derive(Debug, Clone)]
 pub struct ConnectionEnv {
     runtime: Arc<RuntimeContext>,
+    /// Explicit page-buffer-pool ceiling override. `None` defers to the
+    /// `FSQLITE_PAGE_BUFFER_MAX` env var / [`DEFAULT_PAGE_BUFFER_MAX`].
+    page_buffer_max: Option<usize>,
 }

 impl ConnectionEnv {
     /// Create a connection environment from an explicit runtime context.
     #[must_use]
     pub fn new(runtime: Arc<RuntimeContext>) -> Self {
-        Self { runtime }
+        Self {
+            runtime,
+            page_buffer_max: None,
+        }
     }

     /// Access the runtime context that will back newly opened connections.
     #[must_use]
     pub fn runtime(&self) -> &Arc<RuntimeContext> {
         &self.runtime
     }
+
+    /// Override the maximum number of page buffers the pager's buffer pool
+    /// will allocate.
+    ///
+    /// At the standard 4 KiB page size, each buffer consumes ~4 KiB, so
+    /// `262_144` ≈ 1 GiB and `524_288` ≈ 2 GiB.
+    ///
+    /// Pass `None` to revert to the default resolution (env var, then
+    /// compile-time default).
+    pub fn set_page_buffer_max(&mut self, max_buffers: impl Into<Option<usize>>) {
+        self.page_buffer_max = max_buffers.into();
+    }
+
+    /// Returns the explicit page-buffer-pool ceiling, if one has been set.
+    #[must_use]
+    pub fn page_buffer_max(&self) -> Option<usize> {
+        self.page_buffer_max
+    }
 }

 impl Default for ConnectionEnv {
     fn default() -> Self {
         Self {
             runtime: RuntimeContext::global(),
+            page_buffer_max: None,
         }
     }
 }
